{"command": "cd /tmp/sv-9590cd9506104c91b6dc1f425513fd9e/advanced-multi-complexity && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def get_packages(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = get_packages(baseline)
a = get_packages(after)

changes = []
unchanged = []
all_keys = sorted(set(list(b.keys()) + list(a.keys())))
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((k[0], k[1], k[2], bv))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]} | {c[1]} | {c[2]} | {c[3]} -> {c[4]}')
print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]} | {u[1]} | {u[2]} | {u[3]}')
"
